      { key: "twin", label: "Digital Twin", labelZh: "数字孪生" },
      { key: "datacat", label: "Data Catalog", labelZh: "数据目录" },
      { key: "process", label: "Process Automation", labelZh: "流程自动化" },
    ],
  },
  {
    key: "infra",
