3	
4	const LAYERS = ["public", "industry"] as const satisfies readonly Layer[]
5	const STATUSES = ["all", "released", "dev", "none"] as const
6	const VIEWS = ["overview", "panorama", "list"] as const
7	
8	export type StatusFilter = (typeof STATUSES)[number]
9	export type ViewMode = (typeof VIEWS)[number]
10	
11	function parseEnum<T extends readonly string[]>(
12	  value: unknown,
13	  allowed: T,
14	  fallback: T[number],
15	): T[number] {
16	  if (typeof value !== "string") return fallback
17	  return (allowed as readonly string[]).includes(value) ? (value as T[number]) : fallback
18	}
19	
20	function parseString(value: unknown): string | null {
21	  return typeof value === "string" && value.length > 0 ? value : null
22	}
23	
24	export function usePanoramaState() {
25	  const route = useRoute()
26	  const router = useRouter()
27	
28	  const layer = computed<Layer>(() => parseEnum(route.query.layer, LAYERS, "public"))
29	  const primary = computed<string | null>(() => parseString(route.query.primary))
30	  const secondary = computed<string | null>(() => parseString(route.query.secondary))
31	  const status = computed<StatusFilter>(() => parseEnum(route.query.status, STATUSES, "all"))
32	  const viewMode = computed<ViewMode>(() => parseEnum(route.query.view, VIEWS, "overview"))
33	
34	  function push(partial: Record<string, string | null>) {
